-- 027_works_seed.sql
-- '프리즘필터 출판사 관리 저작물 지분 정보' XLSX 시드 — works 738행 + work_authors 5501행
-- 자동 생성(scratchpad xlsx 파서). 026_works_schema.sql 적용 후 실행.
-- 재실행 안전: works는 ON CONFLICT(komca_code) DO NOTHING, work_authors는 기존 작품의 원작자를 정리 후 재삽입.
-- 적용: Supabase 대시보드 SQL 편집기에서 1회 실행

BEGIN;

ON CONFLICT (komca_code) DO NOTHING;

ON CONFLICT (komca_code) DO NOTHING;

ON CONFLICT (komca_code) DO NOTHING;

ON CONFLICT (komca_code) DO NOTHING;

-- 원작자 재삽입 전 시드 대상 작품의 기존 원작자 정리(재실행 안전)
DELETE FROM public.work_authors WHERE work_id IN (SELECT id FROM public.works);





























COMMIT;
